import argparse
import json
import pickle
from pathlib import Path
import numpy as np
import heapq
import glob
import os
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"alpha": 3.0, "beta": 1.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    return 'outdoor'

def coord_to_tuple(c):
    if isinstance(c, np.ndarray): return tuple(np.round(c.astype(float), 6))
    if isinstance(c, (list, tuple)): return tuple(np.round(np.array(c).astype(float), 6))
    return c

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors: return None
    nodes = obs.get("nodes", [])
    if not nodes: return neighbors[0]
    node_dict = {coord_to_tuple(node.get("coords")): node for node in nodes if "coords" in node}
    current_pos = coord_to_tuple(obs.get("robot_pos", np.zeros(2)))
    if current_pos not in node_dict:
        min_d, closest = float('inf'), None
        for nc in node_dict:
            d = np.linalg.norm(np.subtract(nc, current_pos))
            if d < min_d: min_d, closest = d, nc
        if closest is not None: current_pos = closest
    if current_pos not in node_dict:
        best_u, best = -1, neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0)
            if u > best_u: best_u, best = u, n
        return best
    graph = {}
    utilities = {}
    visited = {}
    for coord, node in node_dict.items():
        ns = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in ns if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited[coord] = bool(node.get("visited", False))
    def edge_dist(a, b):
        return np.linalg.norm(np.subtract(a, b))
    def dijkstra(start):
        dists = {start: 0.0}
        prev = {start: None}
        pq = [(0.0, start)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dists.get(u, float('inf')): continue
            for v in graph.get(u, []):
                alt = d + edge_dist(u, v)
                if alt < dists.get(v, float('inf')):
                    dists[v] = alt
                    prev[v] = u
                    heapq.heappush(pq, (alt, v))
        return dists, prev
    all_dists, prev = dijkstra(current_pos)
    alpha = model.get("alpha", 3.0)
    beta = model.get("beta", 1.5)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0 or visited.get(tcoord, True): continue
        d = all_dists.get(tcoord, float('inf'))
        if d == float('inf') or d < 0.01: continue
        score = (util ** beta) / (d ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord
    if best_target is None:
        best_u = -1.0
        best_n = neighbors[0]
        for n_raw in neighbors:
            nc = coord_to_tuple(n_raw)
            u = utilities.get(nc, 0.0)
            if u > best_u:
                best_u = u
                best_n = n_raw
        return best_n
    curr = best_target
    while prev.get(curr) is not None and prev.get(curr) != current_pos:
        curr = prev.get(curr)
    next_coord = curr
    for neigh in neighbors:
        if coord_to_tuple(neigh) == next_coord:
            return neigh
    best_u = -1.0
    best_n = neighbors[0]
    for n_raw in neighbors:
        nc = coord_to_tuple(n_raw)
        u = utilities.get(nc, 0.0)
        if u > best_u:
            best_u = u
            best_n = n_raw
    return best_n

def get_maps(data_path):
    data_path = Path(data_path)
    config_path = data_path / "eval_config.json"
    maps = []
    if config_path.exists():
        with open(config_path, "r") as f:
            config = json.load(f)
        keys = ["maps", "map_paths", "map_list", "files", "map_files", "test_maps"]
        for key in keys:
            if key in config and isinstance(config[key], list) and config[key]:
                for m in config[key]:
                    mpath = Path(str(m))
                    candidates = [data_path / mpath.name, data_path / "maps_eval" / mpath.name, Path("/data") / mpath, Path(os.environ.get("RAB_DATA_DIR", "/data")) / mpath]
                    for cand in candidates:
                        if cand.exists() and cand.suffix.lower() in ['.png', '.jpg', '.jpeg']:
                            maps.append(cand)
                            break
                if maps: break
    if not maps:
        for dname in ["maps_eval", "maps_train"]:
            eval_dir = data_path / dname
            if not eval_dir.exists():
                eval_dir = Path(os.environ.get("RAB_DATA_DIR", "/data")) / dname
            if eval_dir.exists():
                for typ in ["room", "tunnel", "outdoor"]:
                    pattern = str(eval_dir / typ / "*.png")
                    found = glob.glob(pattern)
                    if found:
                        maps.extend([Path(f) for f in sorted(found)])
                if maps: break
    if not maps:
        train_dir = Path(os.environ.get("RAB_DATA_DIR", "/data")) / "maps_train"
        for typ in ["room", "tunnel", "outdoor"]:
            pattern = str(train_dir / typ / "*.png")
            found = sorted(glob.glob(pattern))[:3]
            maps.extend([Path(f) for f in found])
        print("Using 3 training maps per type for local testing.")
    return sorted(set(maps))

def run_evaluation(data_path, checkpoint, output_path):
    model = load_model(checkpoint)
    maps_list = get_maps(data_path)
    print(f"Evaluating on {len(maps_list)} maps.")
    results = []
    per_type = {
        "room": {"explored": [], "dist": [], "success": []},
        "tunnel": {"explored": [], "dist": [], "success": []},
        "outdoor": {"explored": [], "dist": [], "success": []}
    }
    for map_path in maps_list:
        try:
            env_type = get_env_type(map_path)
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            step = 0
            while step < 128:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                step += 1
                if info.get("done", False) or obs.get("explored_rate", 0.0) > 0.9999:
                    break
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", False) or metrics.get("explored_rate", 0.0) >= 0.9999 else 0
            explored = metrics.get("explored_rate", 0.0)
            travel_d = metrics.get("travel_distance", 0.0)
            results.append({
                "map_path": str(map_path),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_d),
                "explored_rate": float(explored)
            })
            per_type[env_type]["explored"].append(explored)
            per_type[env_type]["dist"].append(travel_d if success else None)
            per_type[env_type]["success"].append(success)
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path),
                "env_type": get_env_type(map_path),
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
    total_ep = len(results)
    if total_ep == 0:
        output = {"exploration_score": 0.0, "explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "per_episode": [], "per_type": {}, "total_episodes": 0}
        with open(output_path, "w") as f:
            json.dump(output, f, indent=2)
        return output
    success_rate = sum(r["success"] for r in results) / total_ep
    explored_rate = sum(r["explored_rate"] for r in results) / total_ep
    successful_dists = [r["travel_distance"] for r in results if r["success"] > 0]
    travel_distance = sum(successful_dists) / len(successful_dists) if successful_dists else 0.0
    exploration_score = sum((r["success"] * (300.0 / r["travel_distance"] if r["travel_distance"] > 0 else 0.0)) for r in results) / total_ep
    per_type_summary = {}
    for t, ps in per_type.items():
        ns = len(ps["success"])
        if ns > 0:
            srate = sum(ps["success"]) / ns
            erate = sum(ps["explored"]) / ns
            s_dists = [d for d in ps["dist"] if d is not None]
            dmean = sum(s_dists) / len(s_dists) if s_dists else 0.0
            per_type_summary[t] = {"explored_rate": float(erate), "travel_distance": float(dmean), "success_rate": float(srate)}
    output = {
        "exploration_score": float(exploration_score),
        "explored_rate": float(explored_rate),
        "travel_distance": float(travel_distance),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_summary,
        "total_episodes": total_ep
    }
    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)
    print(f"Evaluation completed with exploration_score: {exploration_score}")
    print(f"Success rate: {success_rate}, Explored: {explored_rate}, Avg dist: {travel_distance}")
    if total_ep <= 9:
        print("Proxy exploration_score based on local test.")
    return output

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
